sections = set(f["s"] for f in files)
for s in sections:
    os.makedirs(os.path.join(BASE_DIR, s), exist_ok=True)
print(f"Criadas {len(sections)} pastas")

ok, errs = 0, []
for i, f in enumerate(files):
    dest = os.path.join(BASE_DIR, f["s"], f["n"])
    if os.path.exists(dest):
        print(f"[{i+1}/{len(files)}] JA EXISTE: {f['s']}/{f['n']}")
        ok += 1
        continue
    try:
        r = requests.get(f["u"], timeout=30)
        if r.status_code == 200:
            with open(dest, 'wb') as fp:
                fp.write(r.content)
            print(f"[{i+1}/{len(files)}] OK ({len(r.content)}B): {f['s']}/{f['n']}")
            ok += 1
        else:
            msg = f"HTTP {r.status_code}: {f['s']}/{f['n']}"
            print(f"[{i+1}/{len(files)}] ERRO {msg}")
            errs.append(msg)
    except Exception as e:
        msg = f"{e}: {f['s']}/{f['n']}"
        print(f"[{i+1}/{len(files)}] EXCECAO {msg}")
        errs.append(msg)
    time.sleep(0.05)

print(f"\nFIM: {ok}/{len(files)} OK")
if errs:
    print("Erros:", errs)
